#include <vector>
#include <algorithm>
#include <limits>

using namespace std;

/**
 * @brief Solves the problem by finding the smallest stable index.
 * 
 * @param nums The input array of integers.
 * @param k The threshold value.
 * @return int64 The smallest stable index, or -1 if none exists.
 */
int64 solve(vector<int64> nums, int64 k) {
    int n = nums.size();
    if (n == 0) {
        return -1;
    }

    // Precompute prefix maximums: prefix_max[i] = max(nums[0...i])
    vector<int64> prefix_max(n);
    prefix_max[0] = nums[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = max(prefix_max[i - 1], nums[i]);
    }

    // Precompute suffix minimums: suffix_min[i] = min(nums[i...n-1])
    vector<int64> suffix_min(n);
    suffix_min[n - 1] = nums[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_min[i] = min(suffix_min[i + 1], nums[i]);
    }

    // Iterate through all indices i to check for stability
    for (int i = 0; i < n; ++i) {
        // Unstable value = max(nums[0..i]) - min(nums[i..n-1])
        int64 unstable_value = prefix_max[i] - suffix_min[i];

        // Check if the index is stable
        if (unstable_value <= k) {
            // Since we are iterating from i=0 upwards, the first one found is the minimum stable index
            return i;
        }
    }

    // If no stable index is found
    return -1;
}
